  1	import { type FC, type KeyboardEvent, type MouseEvent, useState } from 'react';
  2	import { Link } from 'react-router-dom-v5-compat';
  3	import { ConsoleTimestamp } from 'src/components/ConsoleTimestamp/ConsoleTimestamp';
  4	import StatusIcon from 'src/components/status/StatusIcon';
  5	import { getResourceUrl } from 'src/modules/Providers/utils/helpers/getResourceUrl';
  6	import { useForkliftTranslation } from 'src/utils/i18n';
  7	
  8	import type { IoK8sApiCoreV1Pod } from '@kubev2v/types';
  9	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
 10	import { HelperText, HelperTextItem, Pagination, Tooltip } from '@patternfly/react-core';
 11	import { Table, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
 12	import { getKind, getName, getNamespace, getOwnerReference } from '@utils/crds/common/selectors';
 13	import { isEmpty } from '@utils/helpers';
 14	
 15	type PodsTableProps = {
 16	  pods: IoK8sApiCoreV1Pod[];
 17	  showOwner?: boolean;
 18	  limit?: number;
 19	};
 20	
 21	const PAGINATION_THRESHOLD = 10;
 22	
 23	export const PodsTable: FC<PodsTableProps> = ({ limit, pods, showOwner }) => {
 24	  const { t } = useForkliftTranslation();
 25	
 26	  const [currentPage, setCurrentPage] = useState(1);
 27	  const [perPage, setPerPage] = useState(10);
 28	
 29	  // Sort pods to prioritize the one starting with 'forklift-controller-'
 30	  const sortedPods = pods.sort((a, b) => {
 31	    const isForkliftControllerA = a?.metadata?.name?.startsWith('forklift-controller-') ? -1 : 0;
 32	    const isForkliftControllerB = b?.metadata?.name?.startsWith('forklift-controller-') ? -1 : 0;
 33	    return isForkliftControllerA - isForkliftControllerB;
 34	  });
 35	
 36	  const limitedPods = sortedPods?.slice(0, limit);
 37	
 38	  const startIndex = (currentPage - 1) * perPage;
 39	  const endIndex = startIndex + perPage;
 40	  const paginatedPods = limitedPods.slice(startIndex, endIndex);
 41	
 42	  const onSetPage = (_event: MouseEvent | KeyboardEvent | globalThis.MouseEvent, page: number) => {
 43	    setCurrentPage(page);
 44	  };
 45	
 46	  const onPerPageSelect = (
 47	    _event: MouseEvent | KeyboardEvent | globalThis.MouseEvent,
 48	    selectedPerPage: number,
 49	  ) => {
 50	    setPerPage(selectedPerPage);
 51	    setCurrentPage(1); // Reset to the first page
 52	  };
 53	
 54	  const getPodLogsLink = (pod: IoK8sApiCoreV1Pod) =>
 55	    getResourceUrl({
 56	      name: pod.metadata?.name,
 57	      namespace: pod.metadata?.namespace,
 58	      reference: 'pods',
 59	    });
 60	
 61	  if (!limitedPods || isEmpty(limitedPods)) {
 62	    return (
 63	      <HelperText>
 64	        <HelperTextItem>{t('Pods not found')}</HelperTextItem>
 65	      </HelperText>
 66	    );
 67	  }
 68	
 69	  return (
 70	    <>
 71	      {limitedPods.length > PAGINATION_THRESHOLD && (
 72	        <Pagination
 73	          itemCount={limitedPods.length}
 74	          perPage={perPage}
 75	          page={currentPage}
 76	          onSetPage={onSetPage}
 77	          onPerPageSelect={onPerPageSelect}
 78	          variant="top"
 79	        />
 80	      )}
 81	      <Table aria-label="Expandable table" variant="compact">
 82	        <Thead>
 83	          <Tr>
 84	            <Th modifier="fitContent">{t('Pod')}</Th>
 85	            {showOwner && <Th modifier="fitContent">{t('Owner')}</Th>}
 86	            <Th modifier="fitContent">{t('Status')}</Th>
 87	            <Th modifier="fitContent">{t('Logs')}</Th>
 88	            <Th modifier="fitContent">{t('Created at')}</Th>
 89	          </Tr>
 90	        </Thead>
 91	        <Tbody>
 92	          {paginatedPods.map((pod) => (
 93	            <Tr key={pod?.metadata?.uid}>
 94	              <Td modifier="fitContent">
 95	                <ResourceLink
 96	                  kind={getKind(pod)}
 97	                  name={getName(pod)}
 98	                  namespace={getNamespace(pod)}
 99	                />
100	              </Td>
101	              {showOwner && (
102	                <Td modifier="fitContent">
103	                  {getOwnerReference(pod) ? (
104	                    <ResourceLink
105	                      kind={getOwnerReference(pod)?.kind}
106	                      name={getOwnerReference(pod)?.name}
107	                      namespace={getNamespace(pod)}
108	                    />
109	                  ) : (
110	                    ''
111	                  )}
112	                </Td>
113	              )}
114	              <Td modifier="fitContent">
115	                {pod?.status?.phase ? (
116	                  <Tooltip content={pod.status.phase}>
117	                    <StatusIcon phase={pod.status.phase} />
118	                  </Tooltip>
119	                ) : (
120	                  ''
121	                )}
122	              </Td>
123	              <Td modifier="fitContent">
124	                <Link to={`${getPodLogsLink(pod)}/logs`}>{t('Logs')}</Link>
125	              </Td>
126	              <Td modifier="fitContent">
127	                <ConsoleTimestamp timestamp={pod?.metadata?.creationTimestamp ?? ''} />
128	              </Td>
129	            </Tr>
130	          ))}
131	        </Tbody>
132	      </Table>
133	      {limitedPods.length > PAGINATION_THRESHOLD && (
134	        <Pagination
135	          itemCount={limitedPods.length}
136	          perPage={perPage}
137	          page={currentPage}
138	          onSetPage={onSetPage}
139	          onPerPageSelect={onPerPageSelect}
140	          variant="bottom"
141	        />
142	      )}
143	    </>
144	  );
145	};

